<template>
  <div class="processing-analytics">
    <loader :is-visible="isLoading"></loader>
    <div class="widgets-grid">
      <AgentPerformance v-if="isShowAgentPerformence" :AgentPerformenceData="AgentPerformenceData" />

      <FlagReason v-if="isShowAgentPerformence"></FlagReason>

      <FlagRecords v-if="isShowAgentPerformence"></FlagRecords>

      <WorkDateStatusReport v-if="isShowAgentPerformence"></WorkDateStatusReport>
    </div>
  </div>
</template>

<script>
import { analyticsService } from '../../../services/analyticsService';
import AgentPerformance from './widgets/AgentPerformance.vue';
import FlagReason from './widgets/FlagReason.vue';
import FlagRecords from './widgets/FlagRecords.vue';
import WorkDateStatusReport from './widgets/WorkDateStatusReport.vue';

export default {
  name: 'ProcessingAnalytics',
  components: {
    AgentPerformance,
    FlagReason,
    FlagRecords,
    WorkDateStatusReport

  },
  data() {
    return {
      AgentPerformenceData: [],
      GeographicDistributionData: [],
      GetQuarterlyBillingStatsData: [],
      isShowAgentPerformence: false,
      isShowGeographicDistribution: false,
      isLoading: false,


    }
  },

  created: async function () {
    const vm = this;
    vm.isLoading = true;

    try {
      await vm.AgentPerformence();
    } catch (err) {
      console.error(err);
    } finally {
      vm.isLoading = false; // ✅ hide loader after page is ready
    }
  },
  methods: {

    async AgentPerformence() {
      //debugger
      var vm = this;

      try {

        const response = await analyticsService.GetAgentPerformenceData();
        if (response && response.data && response.data.result) {

          vm.AgentPerformenceData = response.data.result;
          vm.isShowAgentPerformence = true;

        }
      } catch (error) {
        console.error('Error loading total revenue trend:', error);
      } finally {
        //this.loading = false;
      }
    },

  }
};
</script>

<style scoped>
.processing-analytics {
  width: 100%;
}

.widgets-grid {
  display: grid;
  /* grid-template-columns: repeat(auto-fit, minmax(400px, 1fr)); */
  gap: 20px;
}
</style>