<template>


  <div class="revenue-analytics w-100 float-left">

    <loader :is-visible="isLoading"></loader>

    <div class="widgets-grid_mainsingle">

      <!-- <GeographicDistribution v-if="isShowGeographicDistribution"
        :GeographicDistributionData="GeographicDistributionData" /> -->

      <RevenueAnalyticswidgets v-if="IsGetQuarterlyBillingStats"
        :GetQuarterlyBillingStatsData="GetQuarterlyBillingStatsData" />
    </div>
    <div class="widgets-grid">
      <TotalRevenueTrendWidget v-if="IsTrendRevenueDataLoaded"
        :quarterly-trend-analysis-data="QuarterlyTrendAnalysisData" :PeakRevenue="PeakRevenue"
        :AverageQuarterly="AverageQuarterly" />

      <BillsVsRevenueWidget v-if="IsTrendRevenueDataLoaded" :quarterly-trend-analysis-data="QuarterlyTrendAnalysisData"
        :TotalBills="TotalBills" :BillRevenueRatio="BillRevenueRatio" />
      <AvgBillAmountWidget v-if="IsTrendRevenueDataLoaded" :quarterly-trend-analysis-data="QuarterlyTrendAnalysisData"
        :MaxAvgBill="MaxAvgBill" :MedianAvgBill="MedianAvgBill" />
      <UniqueClientsWidget v-if="IsTrendRevenueDataLoaded" :quarterly-trend-analysis-data="QuarterlyTrendAnalysisData"
        :PeakClients="PeakClients" :AverageClients="AverageClients" />
      <RevenuePerClientWidget v-if="IsTrendRevenueDataLoaded"
        :quarterly-trend-analysis-data="QuarterlyTrendAnalysisData" :MaxRevPerClient="MaxRevPerClient"
        :AvgRevPerClient="AvgRevPerClient" />
      <YearlyRevenueWidget v-if="IsTrendRevenueDataLoaded" :quarterly-trend-analysis-data="QuarterlyTrendAnalysisData"
        :BestYear="BestYear" :YearlyGrowth="YearlyGrowth" />


    </div>
  </div>
</template>

<script>
import { analyticsService } from '../../../services/analyticsService';

import TotalRevenueTrendWidget from './widgets/TotalRevenueTrendWidget.vue';

import BillsVsRevenueWidget from './widgets/BillsVsRevenueWidget.vue';
import AvgBillAmountWidget from './widgets/AvgBillAmountWidget.vue';
import UniqueClientsWidget from './widgets/UniqueClientsWidget.vue';
import RevenuePerClientWidget from './widgets/RevenuePerClientWidget.vue';
import YearlyRevenueWidget from './widgets/YearlyRevenueWidget.vue';

//import GeographicDistribution from './widgets/GeographicDistribution.vue';
import RevenueAnalyticswidgets from './widgets/RevenueAnalyticswidgets.vue';


export default {
  name: 'RevenueAnalytics',
  components: {

    TotalRevenueTrendWidget,

    BillsVsRevenueWidget,
    AvgBillAmountWidget,
    UniqueClientsWidget,
    RevenuePerClientWidget,
    YearlyRevenueWidget,
    //GeographicDistribution,
    RevenueAnalyticswidgets

  },
  data() {
    return {
      QuarterlyTrendAnalysisData: [],
      IsTrendRevenueDataLoaded: false,
      SummaryItemData: {},
      PeakRevenue: null,
      AverageQuarterly: null,
      TotalBills: null,
      BillRevenueRatio: null,
      MaxAvgBill: null,
      MedianAvgBill: null,
      PeakClients: null,
      AverageClients: null,
      MaxRevPerClient: null,
      AvgRevPerClient: null,
      BestYear: null,
      YearlyGrowth: null,
      isShowGeographicDistribution: false,
      //GeographicDistributionData: [],
      IsGetQuarterlyBillingStats: false,
      GetQuarterlyBillingStatsData: [],
      isLoading: false,

    }
  }, 

  created: async function () {
    //debugger
    const vm = this;
    vm.isLoading = true;

    try {
      await Promise.all([
        vm.loadData(),
        //vm.GeographicDistribution(),
        vm.GetQuarterlyBillingStats()
      ]);
    } catch (err) {
      console.error(err);
    } finally {
      vm.isLoading = false; // ✅ hides only after page is fully ready
    }
  },
  methods: {

    async loadData() {
      //debugger
      var vm = this;
      try {

        const url = `FromYear=2016`
        const response = await analyticsService.GetQuarterlyTrendAnalysis(url);
        if (response && response.data && response.data.result) {

          // this is response.data.result
          const raw = response.data.result;

          // 1️⃣ Parse outer string → array
          const parsedOnce = JSON.parse(raw);

          // 2️⃣ Parse first element → actual array of { key, value }
          const parsedTwice = JSON.parse(parsedOnce[0]);

          // 3️⃣ Find quarterlyData
          const quarterlyItem = parsedTwice.find(
            item => item.key === "quarterlyData"
          );

          const summaryItem = parsedTwice.find(
            item => item.key === "summary"
          );

          // 4️⃣ Parse its value (because it's ALSO a string)
          vm.QuarterlyTrendAnalysisData = JSON.parse(quarterlyItem.value);

          vm.SummaryItemData = JSON.parse(summaryItem.value);

          //////////////////////Total Revenue Trend//////////////////////////////////

          vm.PeakRevenue = vm.SummaryItemData.Peak_Revenue;
          vm.AverageQuarterly = vm.SummaryItemData.Avg_Quarterly_Revenue;

          ///////////////////////Bills vs Revenue////////////////////////////////

          vm.TotalBills = vm.SummaryItemData.Total_Revenue_All_Time;
          vm.BillRevenueRatio = vm.SummaryItemData.Bill_Revenue_Ratio;

          ////////////////////////Avg Bill Amount//////////////////////////////////         

          vm.MaxAvgBill = Math.max(
            ...vm.QuarterlyTrendAnalysisData.map(d => Number(d.Average_Bill_Amount))
          );

          const sortedBills = vm.QuarterlyTrendAnalysisData.map(d => d.Average_Bill_Amount).sort((a, b) => a - b);
          vm.MedianAvgBill = sortedBills[Math.floor(sortedBills.length / 2)];

          /////////////////////////Unique Clients/////////////////////////////////         

          vm.PeakClients = Math.max(
            ...vm.QuarterlyTrendAnalysisData.map(d => Number(d.Unique_Clients))
          );

          const totalClientsAll = vm.QuarterlyTrendAnalysisData.reduce((sum, d) => sum + d.Unique_Clients, 0);
          vm.AverageClients = Math.round(totalClientsAll / vm.QuarterlyTrendAnalysisData.length);

          /////////////////////////Revenue per Client////////////////////////////////////

          const revenuePerClient = vm.QuarterlyTrendAnalysisData.map(d => d.Total_Revenue / d.Unique_Clients);
          vm.MaxRevPerClient = Math.max(...revenuePerClient);
          vm.AvgRevPerClient = revenuePerClient.reduce((sum, val) => sum + val, 0) / revenuePerClient.length;

          /////////////////////////Yearly Revenue Bar/////////////////////////////////////////

          const yearlyRevenue = {};
          vm.QuarterlyTrendAnalysisData.forEach(d => {
            if (!yearlyRevenue[d.Year]) {
              yearlyRevenue[d.Year] = 0;
            }
            yearlyRevenue[d.Year] += d.Total_Revenue;
          });

          const yearlyArray = Object.keys(yearlyRevenue).map(year => ({
            year: parseInt(year),
            revenue: yearlyRevenue[year]
          })).sort((a, b) => a.year - b.year);

          vm.BestYear = yearlyArray.reduce((max, curr) => curr.revenue > max.revenue ? curr : max);

          vm.YearlyGrowth = ((vm.BestYear.revenue - yearlyArray[0].revenue) / yearlyArray[0].revenue * 100).toFixed(1);

          /////////////////////////////////////////////////////////////////

          vm.IsTrendRevenueDataLoaded = true;

        }
      } catch (error) {
        console.error('Error loading total revenue trend:', error);
      } finally {

      }
    },

    // async GeographicDistribution() {
    //  // debugger
    //   var vm = this;

    //   try {

    //     const response = await analyticsService.GetGeographicDistributionofTickets();
    //     if (response && response.data && response.data.result) {

    //       vm.GeographicDistributionData = response.data.result;
    //       vm.isShowGeographicDistribution = true;

    //     }
    //   } catch (error) {
    //     console.error('Error loading total revenue trend:', error);
    //   } finally {

    //   }
    // },
    async GetQuarterlyBillingStats() {
      //debugger
      var vm = this;

      try {

        const url = `FromYear=2016`

        const response = await analyticsService.GetQuarterlyBillingStats(url);
        if (response && response.data && response.data.result) {

          vm.GetQuarterlyBillingStatsData = response.data.result;
          vm.IsGetQuarterlyBillingStats = true;

        }
      } catch (error) {
        console.error('Error loading total revenue trend:', error);
      } finally {

      }
    },
  }

};
</script>

