<template>
  <div class="widget-card dashboard-boxes graph-widget-box bg-white">

    <!-- HEADER -->
    <div class="widget-header graph-widget-heading float-left w-100">
      <div class="widget-title d-flex justify-content-between align-items-center w-100">
        <span>
          <em class="fas fa-chart-bar"></em>
          {{ $t('YearlyRevenueBar') }}
        </span>
        <button class="fullscreen-btn" @click="openFullscreen">
          <em class="fas fa-expand"></em>
        </button>
      </div>
    </div>

    <!-- CHART -->
    <div v-if="loading" class="loading">Loading...</div>
    <div v-else id="yearlyRevenueChart" class="chart-container"></div>

    <!-- MINI STATS -->
    <div class="mini-stats">
      <div class="mini-stat">
        <div class="mini-stat-value">{{ $n(BestYear.year) }}</div>
        <div class="mini-stat-label">{{ $t('BestYear') }}</div>
      </div>

      <div class="mini-stat">
        <div class="mini-stat-value">{{ $n(YearlyGrowth) }}</div>
        <div class="mini-stat-label">{{ $t('Growth(%)') }}</div>
      </div>
    </div>

    <!-- ================= FULLSCREEN ================= -->
    <div v-if="isFullscreen" class="fullscreen-overlay">

      <div class="fullscreen-header">
        <span>{{ $t('YearlyRevenueBar') }}</span>

        <button class="close-btn" @click="closeFullscreen">
          <i class="fas fa-times"></i>
        </button>
      </div>

      <div id="yearlyRevenueChartFullscreen" class="fullscreen-chart"></div>

    </div>

  </div>
</template>

<script>
import * as Plotly from "plotly.js-dist";

export default {
  name: "YearlyRevenueWidget",

  props: {
    QuarterlyTrendAnalysisData: {
      type: Array,
      default: () => []
    },
    BestYear: {
      type: Object,
      default: () => ({ year: null, revenue: null })
    },
    YearlyGrowth: {
      type: [String, Number],
      default: null
    }
  },

  data() {
    return {
      loading: false,
      years: [],
      values: [],
      isFullscreen: false
    };
  },

  mounted() {
    this.loadData();
    window.addEventListener("keydown", this.handleEsc);
  },

  beforeUnmount() {
    window.removeEventListener("keydown", this.handleEsc);
  },

  methods: {

    /* ================= LOAD DATA ================= */
    loadData() {
      this.loading = true;

      try {
        const yearlyData = {};

        this.QuarterlyTrendAnalysisData.forEach(d => {
          if (!yearlyData[d.Year]) yearlyData[d.Year] = 0;
          yearlyData[d.Year] += d.Total_Revenue;
        });

        this.years = Object.keys(yearlyData).sort();

        this.values = this.years.map(year =>
          Math.round(yearlyData[year])
        );

        this.drawChart("yearlyRevenueChart", 280);

      } catch (error) {
        console.error("Yearly revenue error:", error);
      } finally {
        this.loading = false;
      }
    },

    /* ================= DRAW CHART ================= */
    drawChart(containerId, height) {

      const trace = {
        x: this.years,
        y: this.values,
        type: "bar",
        marker: { color: "#14b8a6" }
      };

      const layout = {
        margin: { t: 40, b: 70, l: 60, r: 40 },
        paper_bgcolor: "transparent",
        plot_bgcolor: "transparent",
        height: height,
        xaxis: {
          type: "category",        // IMPORTANT
          tickmode: "linear",      // show sequential ticks
          dtick: 1,                // every value
          tickangle: 0,
          automargin: true
        }
      };

      Plotly.newPlot(
        containerId,
        [trace],
        layout,
        {
          responsive: true,
          displaylogo: false,
          modeBarButtons: [["toImage"]],
          toImageButtonOptions: {
            format: "png",
            filename: "Yearly_Revenue_Bar",
            height: 700,
            width: 1200,
            scale: 2
          }
        }
      );
    },

    /* ================= FULLSCREEN ================= */

    openFullscreen() {
      this.isFullscreen = true;

      this.$nextTick(() => {
        this.drawChart(
          "yearlyRevenueChartFullscreen",
          window.innerHeight - 120
        );
      });
    },

    closeFullscreen() {
      this.isFullscreen = false;
    },

    handleEsc(e) {
      if (e.key === "Escape") {
        this.closeFullscreen();
      }
    }
  }
};
</script>

<style scoped>
/* chart */
.chart-container {
  width: 100%;
  height: 280px;
}

/* header action */
.widget-actions {
  float: right;
}

.fullscreen-btn {
  border: none;
  background: transparent;
  cursor: pointer;
  font-size: 16px;
  color: #6b7280;
}

.fullscreen-btn:hover {
  color: #111827;
}

/* ================= FULLSCREEN ================= */

.fullscreen-overlay {
  position: fixed;
  inset: 0;
  background: #ffffff;
  z-index: 999999999999;
  display: flex;
  flex-direction: column;
}

.fullscreen-header {
  height: 60px;
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 0 25px;
  border-bottom: 1px solid #e5e7eb;
  font-weight: 600;
  font-size: 18px;
}

.fullscreen-chart {
  flex: 1;
  width: 100%;
}

.close-btn {
  border: none;
  background: transparent;
  font-size: 20px;
  cursor: pointer;
}

/* mini stats */
.mini-stats {
  display: flex;
  justify-content: space-around;
  padding: 10px 0;
}

.mini-stat-value {
  font-weight: 600;
}

.mini-stat-label {
  font-size: 12px;
  color: #6b7280;
}
</style>