<template>
    <div
        class="widget-card dashboard-boxes graph-widget-box bg-white mt-2 mb-4"
        :class="{ fullscreen: isFullscreen }"
    >
        <!-- HEADER -->
        <div class="widget-header graph-widget-heading float-left w-100 d-flex justify-content-between align-items-center">
            <div class="widget-title">
                <em class="fa fa-bar-chart"></em>
                {{ $t('FlagRecordsReport') }}
            </div>

            <!-- FULLSCREEN BUTTON -->
            <div class="widget-actions">
                <em                    
                    :class="isFullscreen ? 'fas fa-compress' : 'fas fa-expand'"
                    @click="toggleFullscreen"
                    style="cursor:pointer;font-size:16px"
                    title="Toggle Fullscreen"
                ></em>
            </div>
        </div>

        <!-- CHART -->
        <div id="FlagRecordsReport" class="chart-container"></div>
    </div>
</template>

<script>
import * as Plotly from 'plotly.js-dist';
import { analyticsService } from '../../../../services/analyticsService';

export default {
    name: 'AgentPerformance',

    data() {
        return {
            loading: false,
            FlagRecordsData: [],
            State: [],
            FlagRecords: [],
            isFullscreen: false // ✅ fullscreen state
        };
    },

    mounted() {
        this.loadData();
        window.addEventListener('keydown', this.handleEsc);
    },

    beforeUnmount() {
        window.removeEventListener('keydown', this.handleEsc);
    },

    methods: {

        /* ======================
           FULLSCREEN
        ====================== */

        toggleFullscreen() {
            this.isFullscreen = !this.isFullscreen;

            this.$nextTick(() => {
                Plotly.Plots.resize('FlagRecordsReport');
            });
        },

        handleEsc(e) {
            if (e.key === 'Escape' && this.isFullscreen) {
                this.toggleFullscreen();
            }
        },

        /* ======================
           LOAD DATA
        ====================== */

        async loadData() {

            this.loading = true;

            try {
                const response = await analyticsService.GetFlagRecorsData();

                if (response?.data?.result) {

                    let result = response.data.result;

                    if (typeof result === 'string') {
                        result = JSON.parse(result);
                    }

                    if (Array.isArray(result) && typeof result[0] === 'string') {
                        result = JSON.parse(result[0]);
                    }

                    const dataArray = result.Data || [];

                    this.FlagRecordsData = dataArray;
                    this.State = dataArray.map(x => x.state);
                    this.FlagRecords = dataArray.map(x => x.FlagRecords);

                    this.drawChart();
                }

            } catch (error) {
                console.error('Error loading flag records:', error);
            } finally {
                this.loading = false;
            }
        },

        /* ======================
           DRAW CHART
        ====================== */

        drawChart() {

            const trace = {
                x: this.State,
                y: this.FlagRecords,
                type: 'bar',
                marker: { color: '#699cd5' }
            };

            const layout = {
                margin: { t: 30, b: 40, l: 50, r: 30 },
                paper_bgcolor: 'transparent',
                plot_bgcolor: 'transparent',
                autosize: true,

                xaxis: {
                    automargin: true
                },

                yaxis: {
                    automargin: true
                }
            };

            Plotly.newPlot(
                'FlagRecordsReport',
                [trace],
                layout,
                {
                    responsive: true,
                    displaylogo: false,
                    modeBarButtons: [["toImage"]],
                    toImageButtonOptions: {
                        format: "png",
                        filename: "Flag_Records",
                        height: 700,
                        width: 1000,
                        scale: 2
                    }
                }
            );
        }
    }
};
</script>

<style scoped>

/* NORMAL SIZE */
.chart-container {
    width: 100%;
    height: 350px;
}

/* FULLSCREEN MODE */
.fullscreen {
    position: fixed !important;
    inset: 0;
    width: 100vw !important;
    height: 100vh !important;
    z-index: 999999999999999999;
    margin: 0 !important;
    padding: 20px;
    background: #ffffff;
}

.fullscreen .chart-container {
    height: calc(100vh - 80px) !important;
}

/* smooth animation */
.widget-card {
    transition: all 0.25s ease;
}

</style>